action.command:
cat > /tmp/repro_coopvec_convert.sh <<'EOF'
#!/usr/bin/env bash
REPO=/workspace/DirectXShaderCompiler
HLSL=/tmp/repro_coopvec_convert.hlsl
OUT=/tmp/repro_coopvec_convert.ll
cat > "$HLSL" <<'HLSL'
#include <dx/linalg.h>
using namespace dx::linalg;

typedef vector<half, 16> half16;
ByteAddressBuffer inbuf : register(t0);
RWByteAddressBuffer outbuf : register(u0);

[numthreads(1, 1, 1)]
void main() {
  half16 srcF16 = inbuf.Load<half16>(0);
  InterpretedVector<uint, 4, ComponentEnum::F8_E4M3FN> converted =
      Convert<ComponentEnum::F8_E4M3FN, ComponentEnum::F16>(srcF16);
  outbuf.Store4(0, converted.Data);
}
HLSL
"$REPO/build/bin/dxc" -I "$REPO/tools/clang/lib/Headers/hlsl" -enable-16bit-types -T cs_6_10 -HV 202x -E main "$HLSL" > "$OUT"
echo "=== LinAlgConvert and nearby lines ==="
grep -n -A2 -B4 "linAlgConvert" "$OUT" || true
echo "=== shufflevector from v16 half to v4 half ==="
grep -n "shufflevector <16 x half>" "$OUT" || true
EOF
chmod +x /tmp/repro_coopvec_convert.sh
/tmp/repro_coopvec_convert.sh

