cat > /tmp/repro_coopvec_convert_edges.sh <<'EOF'
#!/usr/bin/env bash
REPO=/workspace/DirectXShaderCompiler
HLSL=/tmp/repro_coopvec_convert_edges.hlsl
OUT=/tmp/repro_coopvec_convert_edges.ll
ERR=/tmp/repro_coopvec_convert_edges.err
cat > "$HLSL" <<'HLSL'
#include <dx/linalg.h>
using namespace dx::linalg;
ByteAddressBuffer inbuf : register(t0);
RWByteAddressBuffer outbuf : register(u0);

[numthreads(1, 1, 1)]
void main() {
  vector<float, 16> srcF32 = inbuf.Load<vector<float, 16> >(0);
  InterpretedVector<uint, 4, ComponentEnum::F8_E5M2> convertedF32 =
      Convert<ComponentEnum::F8_E5M2, ComponentEnum::F32>(srcF32);
  outbuf.Store4(0, convertedF32.Data);

  vector<half, 8> srcF16 = inbuf.Load<vector<half, 8> >(128);
  InterpretedVector<uint, 2, ComponentEnum::F8_E4M3FN> convertedF16 =
      Convert<ComponentEnum::F8_E4M3FN, ComponentEnum::F16>(srcF16);
  outbuf.Store2(16, convertedF16.Data);
}
HLSL
"$REPO/build/bin/dxc" -I "$REPO/tools/clang/lib/Headers/hlsl" -enable-16bit-types -T cs_6_10 -HV 202x -E main "$HLSL" > "$OUT" 2> "$ERR"
cat "$ERR"
grep -n "linAlgConvert" "$OUT"
! grep -q "implicit truncation of vector type" "$ERR"
grep -q '@dx.op.linAlgConvert.v4i32.v16f32' "$OUT"
grep -q '@dx.op.linAlgConvert.v2i32.v8f16' "$OUT"
! grep -q 'shufflevector <16 x float>.*<4 x i32>' "$OUT"
! grep -q 'shufflevector <8 x half>.*<2 x i32>' "$OUT"
EOF
chmod +x /tmp/repro_coopvec_convert_edges.sh
/tmp/repro_coopvec_convert_edges.sh

